1	// @ts-nocheck — Deno runtime (not Node.js)
2	// ==============================================================
3	// LAYERINFINITE — Edge Function: scoring-engine
4	// ==============================================================
5	// Triggered by Supabase cron every 5 minutes.
6	// Refreshes mv_action_scores CONCURRENTLY.
7	// Refreshes mv_episode_patterns nightly (or on demand).
8	//
9	// Deploy: supabase functions deploy scoring-engine
10	// Cron:   Supabase Dashboard → Edge Functions → scoring-engine
11	//         → Schedule: */5 * * * *
12	// ==============================================================
13	
14	import { createClient } from 'https://esm.sh/@supabase/supabase-js@2';
15	
16	const SUPABASE_URL = Deno.env.get('SUPABASE_URL')!;
17	const SUPABASE_SERVICE_ROLE_KEY = Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')!;
18	const LAYERINFINITE_INTERNAL_SECRET = Deno.env.get('LAYERINFINITE_INTERNAL_SECRET');
19	
20	// Internal endpoint to notify API server of cache refresh
21	// (The API server maintains an in-memory score cache with 5-min TTL)
22	const API_CACHE_REFRESH_URL = Deno.env.get('API_CACHE_REFRESH_URL') ?? '';
23	
24	// Staleness threshold: alert if last refresh > 10 min ago (in ms)
25	const STALENESS_THRESHOLD_MS = 10 * 60 * 1000;
26	
27	Deno.serve(async (req: Request): Promise<Response> => {
28	    const startTime = Date.now();
29	
30	    // ── Auth check (for manual invocations) ────────────────────
31	    // Cron invocations come from Supabase infrastructure (trusted).
32	    // Manual invocations require service role key in Authorization header.
33	    const authHeader = req.headers.get('Authorization') ?? '';
34	    const isCronInvocation = req.headers.get('x-supabase-event') === 'cron';
35	
36	    if (!isCronInvocation && (!LAYERINFINITE_INTERNAL_SECRET || authHeader !== `Bearer ${LAYERINFINITE_INTERNAL_SECRET}`)) {
37	        return new Response(
38	            JSON.stringify({ error: 'Unauthorized' }),
39	            { status: 401, headers: { 'Content-Type': 'application/json' } }
40	        );
41	    }
42	
43	    const supabase = createClient(SUPABASE_URL, SUPABASE_SERVICE_ROLE_KEY, {
44	        auth: { persistSession: false }
45	    });
46	
47	    const results: Record<string, unknown> = {};
48	
49	    // ── Step 1: Check staleness ─────────────────────────────────
50	    let lastRefreshAt: Date | null = null;
51	    try {
52	        const { data, error } = await supabase
53	            .from('mv_action_scores')
54	            .select('view_refreshed_at')
55	            .limit(1)
56	            .maybeSingle();
57	
58	        if (!error && data?.view_refreshed_at) {
59	            lastRefreshAt = new Date(data.view_refreshed_at);
60	            const ageMs = Date.now() - lastRefreshAt.getTime();
61	            if (ageMs > STALENESS_THRESHOLD_MS) {
62	                console.warn(`[scoring-engine] STALE: mv_action_scores last refreshed ${Math.round(ageMs / 60000)} mins ago`);
63	                results.staleness_alert = true;
64	                results.last_refresh_age_minutes = Math.round(ageMs / 60000);
65	            }
66	        }
67	    } catch (err) {
68	        console.warn('[scoring-engine] Could not check staleness:', err);
69	    }
70	
71	    // ── Self-healing guard ──────────────────────────────────────
72	    // MV HEALTH RULE: On every execution, verify mv_action_scores row count > 0 when
73	    // fact_outcomes has real rows. If mismatch detected, log warning — Step 2 refresh
74	    // below will fix it. This surfaces silent cron failures in the logs.
75	    try {
76	        const [{ count: realCount, error: realErr }, { count: mvCount, error: mvErr }] = await Promise.all([
77	            supabase.from('fact_outcomes').select('outcome_id', { count: 'exact', head: true }).eq('is_synthetic', false),
78	            supabase.from('mv_action_scores').select('action_id', { count: 'exact', head: true }),
79	        ]);
80	        if (!realErr && !mvErr && (realCount ?? 0) > 0 && (mvCount ?? 0) === 0) {
81	            console.warn('[scoring-engine] SELF-HEAL: mv_action_scores has 0 rows but fact_outcomes has', realCount, 'real outcomes — forcing refresh now');
82	            results.self_heal_triggered = true;
83	        }
84	    } catch (err) {
85	        console.warn('[scoring-engine] Self-heal check failed (non-fatal):', err);
86	    }
87	
88	    // ── Step 2: Refresh mv_action_scores ───────────────────────
89	    const refreshScoresStart = Date.now();
90	    try {
91	        const { error } = await supabase.rpc('refresh_mv_action_scores');
92	        if (error) throw error;
93	        results.mv_action_scores = {
94	            status: 'refreshed',
95	            duration_ms: Date.now() - refreshScoresStart,
96	        };
97	        console.log('[scoring-engine] mv_action_scores refreshed in', Date.now() - refreshScoresStart, 'ms');
98	    } catch (err) {
99	        console.error('[scoring-engine] mv_action_scores refresh failed:', err);
100	        results.mv_action_scores = { status: 'error', error: String(err) };
101	    }
102	
103	    // ── Step 3: Refresh mv_episode_patterns (nightly only) ─────
104	    // Only refresh episodes during nightly window (22:00–06:00 UTC)
105	    // or when triggered manually with ?force_episodes=true
106	    const forceEpisodes = new URL(req.url).searchParams.get('force_episodes') === 'true';
107	    const hourUTC = new Date().getUTCHours();
108	    const isNightlyWindow = hourUTC >= 22 || hourUTC < 6;
109	
110	    if (isNightlyWindow || forceEpisodes) {
111	        const refreshEpisodesStart = Date.now();
112	        try {
113	            const { error } = await supabase.rpc('refresh_mv_episode_patterns');
114	            if (error) throw error;
115	            results.mv_episode_patterns = {
116	                status: 'refreshed',
117	                duration_ms: Date.now() - refreshEpisodesStart,
118	            };
119	            console.log('[scoring-engine] mv_episode_patterns refreshed in', Date.now() - refreshEpisodesStart, 'ms');
120	        } catch (err) {
121	            console.error('[scoring-engine] mv_episode_patterns refresh failed:', err);
122	            results.mv_episode_patterns = { status: 'error', error: String(err) };
123	        }
124	    } else {
125	        results.mv_episode_patterns = { status: 'skipped', reason: 'outside nightly window' };
126	    }
127	
128	    // ── Step 4: Notify API server to refresh score cache ───────
129	    if (API_CACHE_REFRESH_URL) {
130	        try {
131	            const cacheRes = await fetch(`${API_CACHE_REFRESH_URL}/internal/refresh-score-cache`, {
132	                method: 'POST',
133	                headers: {
134	                    'Authorization': `Bearer ${LAYERINFINITE_INTERNAL_SECRET}`,
135	                    'Content-Type': 'application/json',
136	                },
137	                body: JSON.stringify({ triggered_by: 'scoring-engine' }),
138	            });
139	            results.cache_refresh = {
140	                status: cacheRes.ok ? 'notified' : 'failed',
141	                http_status: cacheRes.status,
142	            };
143	        } catch (err) {
144	            // Non-fatal: cache will TTL-expire naturally
145	            console.warn('[scoring-engine] Cache refresh notification failed (non-fatal):', err);
146	            results.cache_refresh = { status: 'skipped', reason: String(err) };
147	        }
148	    } else {
149	        results.cache_refresh = { status: 'skipped', reason: 'API_CACHE_REFRESH_URL not configured' };
150	    }
151	
152	    // ── Response ────────────────────────────────────────────────
153	    const totalDuration = Date.now() - startTime;
154	    const response = {
155	        refreshed: true,
156	        duration_ms: totalDuration,
157	        timestamp: new Date().toISOString(),
158	        results,
159	    };
160	
161	    console.log('[scoring-engine] Complete in', totalDuration, 'ms');
162	
163	    return new Response(
164	        JSON.stringify(response),
165	        { status: 200, headers: { 'Content-Type': 'application/json' } }
166	    );
167	});
