1	// @ts-nocheck — Deno runtime (not Node.js)
2	// ==============================================================
3	// LAYERINFINITE — Edge Function: trend-detector
4	// ==============================================================
5	// Runs nightly via Supabase cron.
6	// Detects:
7	//   1. Degradation alerts: trend_delta < -0.15
8	//   2. Score flip contradictions: success rate change > 0.4 in 7d
9	//
10	// Deploy: supabase functions deploy trend-detector
11	// Cron:   0 2 * * *  (nightly at 02:00 UTC)
12	// ==============================================================
13	
14	import { createClient } from 'https://esm.sh/@supabase/supabase-js@2';
15	
16	const SUPABASE_URL = Deno.env.get('SUPABASE_URL')!;
17	const SUPABASE_SERVICE_ROLE_KEY = Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')!;
18	const LAYERINFINITE_INTERNAL_SECRET = Deno.env.get('LAYERINFINITE_INTERNAL_SECRET');
19	
20	// Thresholds
21	const DEGRADATION_THRESHOLD = -0.15;
22	const SCORE_FLIP_THRESHOLD = 0.4;
23	
24	Deno.serve(async (req: Request): Promise<Response> => {
25	    const startTime = Date.now();
26	
27	    // ── Auth check ─────────────────────────────────────────────
28	    const authHeader = req.headers.get('Authorization') ?? '';
29	    const isCronInvocation = req.headers.get('x-supabase-event') === 'cron';
30	
31	    if (!isCronInvocation && (!LAYERINFINITE_INTERNAL_SECRET || authHeader !== `Bearer ${LAYERINFINITE_INTERNAL_SECRET}`)) {
32	        return new Response(
33	            JSON.stringify({ error: 'Unauthorized' }),
34	            { status: 401, headers: { 'Content-Type': 'application/json' } }
35	        );
36	    }
37	
38	    const supabase = createClient(SUPABASE_URL, SUPABASE_SERVICE_ROLE_KEY, {
39	        auth: { persistSession: false }
40	    });
41	
42	    const results: Record<string, unknown> = {
43	        degradation_alerts: { inserted: 0, errors: 0 },
44	        trend_changes: { inserted: 0, errors: 0 },
45	    };
46	
47	    // ── Step 1: Detect degradation (trend_delta < -0.15) ───────
48	    try {
49	        const { data: degraded, error: queryErr } = await supabase
50	            .from('mv_action_scores')
51	            .select('action_id, context_id, customer_id, action_name, trend_delta, raw_success_rate, weighted_success_rate, total_attempts')
52	            .not('trend_delta', 'is', null)
53	            .lt('trend_delta', DEGRADATION_THRESHOLD);
54	
55	        if (queryErr) {
56	            console.error('[trend-detector] Degradation query failed:', queryErr.message);
57	            (results.degradation_alerts as any).error = queryErr.message;
58	        } else if (degraded && degraded.length > 0) {
59	            console.log(`[trend-detector] Found ${degraded.length} degraded actions`);
60	
61	            for (const row of degraded) {
62	                // Check if alert already exists for this action+context in the last 24h
63	                const { data: existing } = await supabase
64	                    .from('degradation_alert_events')
65	                    .select('alert_id')
66	                    .eq('action_id', row.action_id)
67	                    .eq('context_id', row.context_id)
68	                    .eq('customer_id', row.customer_id)
69	                    .gte('detected_at', new Date(Date.now() - 24 * 60 * 60 * 1000).toISOString())
70	                    .limit(1)
71	                    .maybeSingle();
72	
73	                if (existing) {
74	                    // Already alerted in last 24h — skip duplicate
75	                    continue;
76	                }
77	
78	                // Compute previous success rate from trend_delta
79	                const currentRate = row.weighted_success_rate ?? row.raw_success_rate ?? 0;
80	                const previousRate = currentRate - (row.trend_delta ?? 0);
81	
82	                const { error: insertErr } = await supabase
83	                    .from('degradation_alert_events')
84	                    .insert({
85	                        action_id: row.action_id,
86	                        context_id: row.context_id,
87	                        customer_id: row.customer_id,
88	                        action_name: row.action_name,
89	                        trend_delta: row.trend_delta,
90	                        current_success_rate: currentRate,
91	                        previous_success_rate: Math.max(0, previousRate),
92	                        total_attempts: row.total_attempts,
93	                    });
94	
95	                if (insertErr) {
96	                    console.error('[trend-detector] Alert insert failed:', insertErr.message);
97	                    (results.degradation_alerts as any).errors++;
98	                } else {
99	                    (results.degradation_alerts as any).inserted++;
100	                }
101	            }
102	        } else {
103	            console.log('[trend-detector] No degraded actions found');
104	        }
105	    } catch (err) {
106	        console.error('[trend-detector] Degradation detection error:', err);
107	        (results.degradation_alerts as any).error = String(err);
108	    }
109	
110	    // ── Step 2: Detect score flips (>0.4 magnitude in 7 days) ──
111	    try {
112	        // Query current week vs previous week success rates
113	        // We use mv_action_scores which already has the raw and weighted rates
114	        const { data: allScores, error: scoresErr } = await supabase
115	            .from('mv_action_scores')
116	            .select('action_id, context_id, customer_id, action_name, raw_success_rate, weighted_success_rate, trend_delta, total_attempts')
117	            .not('trend_delta', 'is', null);
118	
119	        if (scoresErr) {
120	            console.error('[trend-detector] Score flip query failed:', scoresErr.message);
121	            (results.trend_changes as any).error = scoresErr.message;
122	        } else if (allScores && allScores.length > 0) {
123	            for (const row of allScores) {
124	                const currentRate = row.weighted_success_rate ?? row.raw_success_rate ?? 0;
125	                const trendDelta = row.trend_delta ?? 0;
126	                // Approximate previous rate from delta
127	                const previousRate = currentRate - trendDelta;
128	                const flipMagnitude = Math.abs(trendDelta);
129	
130	                if (flipMagnitude < SCORE_FLIP_THRESHOLD) continue;
131	
132	                // Check if event already exists in last 24h
133	                const { data: existing } = await supabase
134	                    .from('trend_change_events')
135	                    .select('event_id')
136	                    .eq('action_id', row.action_id)
137	                    .eq('context_id', row.context_id)
138	                    .eq('customer_id', row.customer_id)
139	                    .gte('detected_at', new Date(Date.now() - 24 * 60 * 60 * 1000).toISOString())
140	                    .limit(1)
141	                    .maybeSingle();
142	
143	                if (existing) continue;
144	
145	                const { error: insertErr } = await supabase
146	                    .from('trend_change_events')
147	                    .insert({
148	                        action_id: row.action_id,
149	                        context_id: row.context_id,
150	                        customer_id: row.customer_id,
151	                        action_name: row.action_name,
152	                        old_success_rate: Math.max(0, Math.min(1, previousRate)),
153	                        new_success_rate: currentRate,
154	                        score_flip_magnitude: Math.round(flipMagnitude * 10000) / 10000,
155	                        affected_outcomes_count: row.total_attempts ?? 0,
156	                    });
157	
158	                if (insertErr) {
159	                    console.error('[trend-detector] Trend change insert failed:', insertErr.message);
160	                    (results.trend_changes as any).errors++;
161	                } else {
162	                    (results.trend_changes as any).inserted++;
163	                }
164	            }
165	        }
166	    } catch (err) {
167	        console.error('[trend-detector] Score flip detection error:', err);
168	        (results.trend_changes as any).error = String(err);
169	    }
170	
171	    // ── Step 3: Latency spike detection (Gap 1) ──────────────
172	    results.latency_spikes = { inserted: 0, errors: 0 };
173	    try {
174	        const LATENCY_SPIKE_THRESHOLD = 3.0;
175	
176	        const { data: latencySpikes, error: latencyErr } = await supabase
177	            .from('mv_action_scores')
178	            .select(`
179	                action_id, customer_id, context_id,
180	                latency_p95_ms, latency_p95_baseline_ms,
181	                latency_spike_ratio
182	            `)
183	            .not('latency_spike_ratio', 'is', null)
184	            .gte('latency_spike_ratio', LATENCY_SPIKE_THRESHOLD)
185	            .gte('total_attempts', 10);
186	
187	        if (latencyErr) {
188	            console.error('[trend-detector] Latency spike query failed:', latencyErr.message);
189	            (results.latency_spikes as any).error = latencyErr.message;
190	        } else if (latencySpikes && latencySpikes.length > 0) {
191	            console.log(`[trend-detector] Found ${latencySpikes.length} latency spikes`);
192	
193	            for (const spike of latencySpikes) {
194	                // 24h dedup
195	                const { data: existing } = await supabase
196	                    .from('degradation_alert_events')
197	                    .select('alert_id')
198	                    .eq('action_id', spike.action_id)
199	                    .eq('context_id', spike.context_id)
200	                    .eq('customer_id', spike.customer_id)
201	                    .eq('alert_type', 'latency_spike')
202	                    .gte('detected_at', new Date(Date.now() - 24 * 60 * 60 * 1000).toISOString())
203	                    .limit(1)
204	                    .maybeSingle();
205	
206	                if (existing) continue;
207	
208	                const { error: insertErr } = await supabase
209	                    .from('degradation_alert_events')
210	                    .insert({
211	                        customer_id: spike.customer_id,
212	                        action_id: spike.action_id,
213	                        context_id: spike.context_id,
214	                        alert_type: 'latency_spike',
215	                        severity: spike.latency_spike_ratio >= 5.0 ? 'critical' : 'warning',
216	                        current_value: spike.latency_p95_ms,
217	                        baseline_value: spike.latency_p95_baseline_ms,
218	                        spike_ratio: spike.latency_spike_ratio,
219	                        message: `p95 latency ${spike.latency_p95_ms}ms is ${spike.latency_spike_ratio.toFixed(1)}x above 30-day baseline (${spike.latency_p95_baseline_ms}ms)`,
220	                    });
221	
222	                if (insertErr) {
223	                    console.error('[trend-detector] Latency alert insert failed:', insertErr.message);
224	                    (results.latency_spikes as any).errors++;
225	                } else {
226	                    (results.latency_spikes as any).inserted++;
227	                }
228	            }
229	        } else {
230	            console.log('[trend-detector] No latency spikes found');
231	        }
232	    } catch (err) {
233	        console.error('[trend-detector] Latency spike detection error:', err);
234	        (results.latency_spikes as any).error = String(err);
235	    }
236	
237	    // ── Step 4: Coordinated failure detection (Gap 3) ──────────
238	    results.coordinated_failures = { inserted: 0, errors: 0 };
239	    try {
240	        const COORDINATION_WINDOW_MINUTES = 15;
241	        const MIN_AGENTS_FOR_COORDINATION = 3;
242	
243	        const { data: coordinatedFailures, error: coordErr } = await supabase.rpc(
244	            'detect_coordinated_failures',
245	            {
246	                window_minutes: COORDINATION_WINDOW_MINUTES,
247	                min_agent_count: MIN_AGENTS_FOR_COORDINATION,
248	            }
249	        );
250	
251	        if (coordErr) {
252	            console.error('[trend-detector] Coordinated failure query failed:', coordErr.message);
253	            (results.coordinated_failures as any).error = coordErr.message;
254	        } else if (coordinatedFailures && coordinatedFailures.length > 0) {
255	            console.log(`[trend-detector] Found ${coordinatedFailures.length} coordinated failures`);
256	
257	            for (const failure of coordinatedFailures) {
258	                // 1-hour dedup (shorter than 24h — coordinated failures can recur hourly)
259	                const { data: recentAlert } = await supabase
260	                    .from('degradation_alert_events')
261	                    .select('alert_id')
262	                    .eq('customer_id', failure.customer_id)
263	                    .eq('alert_type', 'coordinated_failure')
264	                    .eq('action_id', failure.action_id)
265	                    .gte('detected_at', new Date(Date.now() - 60 * 60 * 1000).toISOString())
266	                    .limit(1)
267	                    .maybeSingle();
268	
269	                if (recentAlert) continue;
270	
271	                const { error: insertErr } = await supabase
272	                    .from('degradation_alert_events')
273	                    .insert({
274	                        customer_id: failure.customer_id,
275	                        action_id: failure.action_id,
276	                        alert_type: 'coordinated_failure',
277	                        severity: 'critical',
278	                        affected_agent_count: failure.agent_count,
279	                        message: `${failure.agent_count} agents all failed "${failure.action_name}" within ${COORDINATION_WINDOW_MINUTES} minutes. Likely shared infrastructure failure. Escalate to platform team immediately.`,
280	                    });
281	
282	                if (insertErr) {
283	                    console.error('[trend-detector] Coordinated failure alert insert failed:', insertErr.message);
284	                    (results.coordinated_failures as any).errors++;
285	                } else {
286	                    (results.coordinated_failures as any).inserted++;
287	                }
288	            }
289	        } else {
290	            console.log('[trend-detector] No coordinated failures found');
291	        }
292	    } catch (err) {
293	        console.error('[trend-detector] Coordinated failure detection error:', err);
294	        (results.coordinated_failures as any).error = String(err);
295	    }
296	
297	    // TODO: Seasonal anomaly detection (Gap 4)
298	    // Build after 90 days of production data.
299	    // Requires: day_of_week + hour_of_day columns
300	    // in mv_action_scores baseline comparison.
301	    // Trigger: Black Friday / month-end /
302	    // scheduled batch job patterns.
303	    // Data already being collected via timestamp.
304	
305	    // ── Response ────────────────────────────────────────────────
306	    const totalDuration = Date.now() - startTime;
307	    const response = {
308	        completed: true,
309	        duration_ms: totalDuration,
310	        timestamp: new Date().toISOString(),
311	        thresholds: {
312	            degradation: DEGRADATION_THRESHOLD,
313	            score_flip: SCORE_FLIP_THRESHOLD,
314	        },
315	        results,
316	    };
317	
318	    console.log('[trend-detector] Complete in', totalDuration, 'ms —',
319	        JSON.stringify(results));
320	
321	    return new Response(
322	        JSON.stringify(response),
323	        { status: 200, headers: { 'Content-Type': 'application/json' } }
324	    );
325	});
