1	// @ts-nocheck — Deno runtime (not Node.js)
2	// ==============================================================
3	// LAYERINFINITE — Edge Function: cold-start-bootstrap
4	// ==============================================================
5	// Triggered when a new agent is registered.
6	//
7	// 4-Stage Cold Start Protocol:
8	//   Stage 1: Inject synthetic priors from dim_institutional_knowledge
9	//   Stage 2: Cap confidence multiplier at 0.3 (handled by policy-engine)
10	//   Stage 3: Return all available actions (force exploration, handled by policy-engine)
11	//   Stage 4: Cross-agent transfer — if same-type agent exists with 10+ outcomes,
12	//            pull their patterns as priors for the new agent
13	//
14	// Synthetic priors have is_synthetic = TRUE.
15	// The mv_action_scores view filters WHERE is_synthetic = FALSE,
16	// so priors NEVER inflate real scores.
17	//
18	// Invocation:
19	//   POST /functions/v1/cold-start-bootstrap
20	//   Body: { "agent_id": "<uuid>", "customer_id": "<uuid>" }
21	//
22	// Deploy: supabase functions deploy cold-start-bootstrap
23	// ==============================================================
24	
25	import { createClient } from 'https://esm.sh/@supabase/supabase-js@2';
26	
27	const SUPABASE_URL = Deno.env.get('SUPABASE_URL')!;
28	const SUPABASE_SERVICE_ROLE_KEY = Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')!;
29	const LAYERINFINITE_INTERNAL_SECRET = Deno.env.get('LAYERINFINITE_INTERNAL_SECRET');
30	
31	// How many synthetic priors to inject per action-context pair
32	const SYNTHETIC_PRIOR_COUNT = 5;
33	
34	// Minimum outcomes required for cross-agent transfer donor
35	const MIN_DONOR_OUTCOMES = 10;
36	
37	interface TransferEvent {
38	    source: 'cross_agent' | 'institutional_knowledge';
39	    donor_agent_id: string | null;
40	    priors_inserted: number;
41	    context_types: string[];
42	}
43	
44	Deno.serve(async (req: Request): Promise<Response> => {
45	    const startTime = Date.now();
46	
47	    // ── Auth check ─────────────────────────────────────────────
48	    const authHeader = req.headers.get('Authorization') ?? '';
49	    if (!LAYERINFINITE_INTERNAL_SECRET || authHeader !== `Bearer ${LAYERINFINITE_INTERNAL_SECRET}`) {
50	        return new Response(
51	            JSON.stringify({ error: 'Unauthorized' }),
52	            { status: 401, headers: { 'Content-Type': 'application/json' } }
53	        );
54	    }
55	
56	    // ── Parse request body ─────────────────────────────────────
57	    let body: { agent_id: string; customer_id: string };
58	    try {
59	        body = await req.json();
60	        if (!body.agent_id || !body.customer_id) {
61	            throw new Error('Missing agent_id or customer_id');
62	        }
63	    } catch (err) {
64	        return new Response(
65	            JSON.stringify({ error: 'Invalid request body', details: String(err) }),
66	            { status: 400, headers: { 'Content-Type': 'application/json' } }
67	        );
68	    }
69	
70	    const supabase = createClient(SUPABASE_URL, SUPABASE_SERVICE_ROLE_KEY, {
71	        auth: { persistSession: false }
72	    });
73	
74	    const { agent_id: agentId, customer_id: customerId } = body;
75	
76	    // ── Fetch the new agent's metadata ─────────────────────────
77	    const { data: agent, error: agentErr } = await supabase
78	        .from('dim_agents')
79	        .select('agent_type, customer_id')
80	        .eq('agent_id', agentId)
81	        .single();
82	
83	    if (agentErr || !agent) {
84	        return new Response(
85	            JSON.stringify({ error: 'Agent not found', details: agentErr?.message }),
86	            { status: 404, headers: { 'Content-Type': 'application/json' } }
87	        );
88	    }
89	
90	    const agentType = agent.agent_type;
91	    const transferEvents: TransferEvent[] = [];
92	    let totalPriorsInserted = 0;
93	
94	    // ── Stage 4: Cross-agent transfer ──────────────────────────
95	    // Find same-type agents from the same customer with enough history
96	    const { data: donorAgents } = await supabase
97	        .from('dim_agents')
98	        .select('agent_id')
99	        .eq('agent_type', agentType)
100	        .eq('customer_id', customerId)
101	        .neq('agent_id', agentId)  // exclude the new agent itself
102	        .eq('is_active', true);
103	
104	    let crossAgentTransferred = false;
105	
106	    if (donorAgents && donorAgents.length > 0) {
107	        for (const donor of donorAgents) {
108	            // Check if this donor has enough real outcomes
109	            const { count } = await supabase
110	                .from('fact_outcomes')
111	                .select('outcome_id', { count: 'exact', head: true })
112	                .eq('agent_id', donor.agent_id)
113	                .eq('is_synthetic', false);
114	
115	            if (count !== null && count >= MIN_DONOR_OUTCOMES) {
116	                // Found a valid donor — pull their outcome patterns
117	                // Get distinct context_ids the donor has operated in
118	                const { data: donorContexts } = await supabase
119	                    .from('fact_outcomes')
120	                    .select('context_id')
121	                    .eq('agent_id', donor.agent_id)
122	                    .eq('is_synthetic', false);
123	
124	                const contextIdSet = new Set<string>();
125	                for (const r of (donorContexts ?? [])) {
126	                    contextIdSet.add(String((r as any).context_id));
127	                }
128	                const uniqueContextIds = Array.from(contextIdSet);
129	
130	                // For each context, look up institutional knowledge patterns
131	                const contextTypes: string[] = [];
132	                for (const ctxId of uniqueContextIds) {
133	                    // Resolve context_id → issue_type
134	                    const { data: ctx } = await supabase
135	                        .from('dim_contexts')
136	                        .select('issue_type')
137	                        .eq('context_id', ctxId)
138	                        .single();
139	
140	                    if (!ctx) continue;
141	                    contextTypes.push(ctx.issue_type);
142	
143	                    // Pull institutional knowledge for this context type
144	                    const { data: patterns } = await supabase
145	                        .from('dim_institutional_knowledge')
146	                        .select('action_id, avg_success_rate, sample_count')
147	                        .eq('context_type', ctx.issue_type);
148	
149	                    if (!patterns || patterns.length === 0) continue;
150	
151	                    // Insert synthetic priors for the new agent
152	                    for (const pattern of patterns) {
153	                        const syntheticRows = generateSyntheticPriors(
154	                            agentId,
155	                            pattern.action_id,
156	                            ctxId,
157	                            customerId,
158	                            pattern.avg_success_rate,
159	                            SYNTHETIC_PRIOR_COUNT
160	                        );
161	
162	                        const { error: insertErr } = await supabase
163	                            .from('fact_outcomes')
164	                            .insert(syntheticRows);
165	
166	                        if (!insertErr) {
167	                            totalPriorsInserted += syntheticRows.length;
168	                        } else {
169	                            console.error(`[cold-start] Insert failed for action ${pattern.action_id}:`, insertErr.message);
170	                        }
171	                    }
172	                }
173	
174	                transferEvents.push({
175	                    source: 'cross_agent',
176	                    donor_agent_id: donor.agent_id,
177	                    priors_inserted: totalPriorsInserted,
178	                    context_types: contextTypes,
179	                });
180	
181	                crossAgentTransferred = true;
182	                break;  // Use the first valid donor
183	            }
184	        }
185	    }
186	
187	    // ── Stage 1: Institutional knowledge fallback ──────────────
188	    // If no cross-agent transfer was possible, use global averages
189	    if (!crossAgentTransferred) {
190	        // Get the customer's industry for better matching
191	        const { data: customer } = await supabase
192	            .from('dim_customers')
193	            .select('industry')
194	            .eq('customer_id', customerId)
195	            .single();
196	
197	        const industry = customer?.industry ?? null;
198	
199	        // Fetch all institutional knowledge (filtered by industry if available)
200	        let knowledgeQuery = supabase
201	            .from('dim_institutional_knowledge')
202	            .select('action_id, context_type, avg_success_rate, sample_count');
203	
204	        if (industry) {
205	            knowledgeQuery = knowledgeQuery.eq('industry', industry);
206	        }
207	
208	        const { data: knowledge } = await knowledgeQuery;
209	
210	        if (knowledge && knowledge.length > 0) {
211	            // Group by context_type and resolve to context_ids
212	            const contextTypeMap = new Map<string, string>();
213	
214	            for (const k of knowledge) {
215	                if (!contextTypeMap.has(k.context_type)) {
216	                    // Try to find existing context
217	                    const { data: ctx } = await supabase
218	                        .from('dim_contexts')
219	                        .select('context_id')
220	                        .eq('issue_type', k.context_type)
221	                        .limit(1)
222	                        .maybeSingle();
223	
224	                    if (ctx) {
225	                        contextTypeMap.set(k.context_type, ctx.context_id);
226	                    }
227	                }
228	            }
229	
230	            const contextTypes: string[] = [];
231	            for (const k of knowledge) {
232	                const contextId = contextTypeMap.get(k.context_type);
233	                if (!contextId) continue;
234	
235	                contextTypes.push(k.context_type);
236	
237	                const syntheticRows = generateSyntheticPriors(
238	                    agentId,
239	                    k.action_id,
240	                    contextId,
241	                    customerId,
242	                    k.avg_success_rate,
243	                    SYNTHETIC_PRIOR_COUNT
244	                );
245	
246	                const { error: insertErr } = await supabase
247	                    .from('fact_outcomes')
248	                    .insert(syntheticRows);
249	
250	                if (!insertErr) {
251	                    totalPriorsInserted += syntheticRows.length;
252	                } else {
253	                    console.error(`[cold-start] Global insert failed for action ${k.action_id}:`, insertErr.message);
254	                }
255	            }
256	
257	            transferEvents.push({
258	                source: 'institutional_knowledge',
259	                donor_agent_id: null,
260	                priors_inserted: totalPriorsInserted,
261	                context_types: [...new Set(contextTypes)],
262	            });
263	        }
264	    }
265	
266	    // ── Log transfer event to trust audit ──────────────────────
267	    if (totalPriorsInserted > 0) {
268	        await supabase.from('agent_trust_audit').insert({
269	            agent_id: agentId,
270	            customer_id: customerId,
271	            event_type: 'created',
272	            old_score: null,
273	            new_score: 0.7,
274	            old_status: null,
275	            new_status: 'trusted',
276	            performed_by: 'cold-start-bootstrap',
277	            reason: `Cold start: inserted ${totalPriorsInserted} synthetic priors via ${crossAgentTransferred ? 'cross-agent transfer' : 'institutional knowledge'
278	                }`,
279	        });
280	    }
281	
282	    // ── Response ────────────────────────────────────────────────
283	    const totalDuration = Date.now() - startTime;
284	    const response = {
285	        completed: true,
286	        agent_id: agentId,
287	        agent_type: agentType,
288	        duration_ms: totalDuration,
289	        total_priors_inserted: totalPriorsInserted,
290	        transfer_events: transferEvents,
291	        strategy: crossAgentTransferred ? 'cross_agent_transfer' : 'institutional_knowledge_fallback',
292	        timestamp: new Date().toISOString(),
293	    };
294	
295	    console.log('[cold-start-bootstrap] Result:', JSON.stringify(response));
296	
297	    return new Response(
298	        JSON.stringify(response),
299	        {
300	            status: 200,
301	            headers: { 'Content-Type': 'application/json' },
302	        }
303	    );
304	});
305	
306	// ── Helper: generate synthetic prior outcome rows ──────────────
307	// Creates N fake outcome rows based on the avg_success_rate.
308	// All rows have is_synthetic = TRUE and a deterministic session_id.
309	function generateSyntheticPriors(
310	    agentId: string,
311	    actionId: string,
312	    contextId: string,
313	    customerId: string,
314	    avgSuccessRate: number,
315	    count: number
316	): Array<Record<string, unknown>> {
317	    const rows: Array<Record<string, unknown>> = [];
318	    const syntheticSessionId = crypto.randomUUID();
319	
320	    for (let i = 0; i < count; i++) {
321	        // Deterministic success based on avg rate:
322	        // First floor(rate * count) rows succeed, rest fail
323	        const success = i < Math.round(avgSuccessRate * count);
324	
325	        rows.push({
326	            agent_id: agentId,
327	            action_id: actionId,
328	            context_id: contextId,
329	            customer_id: customerId,
330	            session_id: syntheticSessionId,
331	            success,
332	            is_synthetic: true,
333	            is_deleted: false,
334	            salience_score: 0.0,  // zero salience → won't survive pruning
335	            raw_context: { source: 'cold-start-bootstrap', prior_rate: avgSuccessRate },
336	        });
337	    }
338	
339	    return rows;
340	}
341

1	// @ts-nocheck — Deno runtime (not Node.js)
2	// ==============================================================
3	// LAYERINFINITE — Edge Function: pruning-scheduler
4	// ==============================================================
5	// Runs nightly via Supabase cron.
6	//
7	// Three-stage data lifecycle:
8	//   1. ARCHIVE: Move fact_outcomes rows WHERE timestamp < NOW() - 90 days
9	//      AND salience_score < 0.01 → Compress into fact_outcomes_archive (100:1)
10	//   2. COLD DELETE: Delete fact_outcomes_archive rows WHERE timestamp < NOW() - 365 days
11	//      (patterns preserved forever in dim_institutional_knowledge)
12	//   3. SALIENCE FILTER LOG: Report stats on salience-based downsampling
13	//
14	// ⚠️ DESTRUCTIVE OPERATION — take backup before first run
15	//
16	// Deploy: supabase functions deploy pruning-scheduler
17	// Cron:   0 3 * * *  (nightly at 03:00 UTC)
18	// ==============================================================
19	
20	import { createClient } from 'https://esm.sh/@supabase/supabase-js@2';
21	
22	const SUPABASE_URL = Deno.env.get('SUPABASE_URL')!;
23	const SUPABASE_SERVICE_ROLE_KEY = Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')!;
24	const LAYERINFINITE_INTERNAL_SECRET = Deno.env.get('LAYERINFINITE_INTERNAL_SECRET');
25	
26	// Retention windows
27	const HOT_RETENTION_DAYS = 90;
28	const COLD_RETENTION_DAYS = 365;
29	const COMPRESSION_RATIO = 100;
30	
31	Deno.serve(async (req: Request): Promise<Response> => {
32	    const startTime = Date.now();
33	
34	    // ── Auth check ─────────────────────────────────────────────
35	    const authHeader = req.headers.get('Authorization') ?? '';
36	    const isCronInvocation = req.headers.get('x-supabase-event') === 'cron';
37	
38	    if (!isCronInvocation && (!LAYERINFINITE_INTERNAL_SECRET || authHeader !== `Bearer ${LAYERINFINITE_INTERNAL_SECRET}`)) {
39	        return new Response(
40	            JSON.stringify({ error: 'Unauthorized' }),
41	            { status: 401, headers: { 'Content-Type': 'application/json' } }
42	        );
43	    }
44	
45	    const supabase = createClient(SUPABASE_URL, SUPABASE_SERVICE_ROLE_KEY, {
46	        auth: { persistSession: false }
47	    });
48	
49	    const results: Record<string, unknown> = {
50	        stage1_archive: { groups_archived: 0, rows_deleted: 0, errors: 0 },
51	        stage2_cold_delete: { rows_deleted: 0, errors: 0 },
52	        stage3_stats: { total_hot_rows: 0, low_salience_rows: 0 },
53	    };
54	
55	    // ── Stage 1: Archive old low-salience outcomes ─────────────
56	    // fact_outcomes → fact_outcomes_archive (compressed aggregates)
57	    try {
58	        const cutoffDate = new Date(Date.now() - HOT_RETENTION_DAYS * 24 * 60 * 60 * 1000).toISOString();
59	
60	        // Find groups of old, low-salience outcomes to archive
61	        // Group by agent_id, action_id, context_id, customer_id (one archive row per group)
62	        const { data: oldOutcomes, error: queryErr } = await supabase
63	            .from('fact_outcomes')
64	            .select('outcome_id, agent_id, action_id, context_id, customer_id, success, response_time_ms, timestamp')
65	            .lt('timestamp', cutoffDate)
66	            .lt('salience_score', 0.01)
67	            .eq('is_deleted', false)
68	            .eq('is_synthetic', false)
69	            .order('timestamp', { ascending: true });
70	
71	        if (queryErr) {
72	            console.error('[pruning] Stage 1 query failed:', queryErr.message);
73	            (results.stage1_archive as any).errors++;
74	        } else if (oldOutcomes && oldOutcomes.length > 0) {
75	            console.log(`[pruning] Stage 1: Found ${oldOutcomes.length} rows to archive`);
76	
77	            // Group by (agent_id, action_id, context_id, customer_id)
78	            const groups = new Map<string, typeof oldOutcomes>();
79	            for (const row of oldOutcomes) {
80	                const key = `${row.agent_id}:${row.action_id}:${row.context_id}:${row.customer_id}`;
81	                if (!groups.has(key)) groups.set(key, []);
82	                groups.get(key)!.push(row);
83	            }
84	
85	            for (const [, rows] of groups) {
86	                const first = rows[0];
87	                const totalOutcomes = rows.length;
88	                const totalSuccesses = rows.filter((r: any) => r.success).length;
89	                const avgResponseTime = rows
90	                    .filter((r: any) => r.response_time_ms !== null)
91	                    .reduce((sum: number, r: any) => sum + (r.response_time_ms ?? 0), 0) /
92	                    Math.max(rows.filter((r: any) => r.response_time_ms !== null).length, 1);
93	
94	                const timestamps = rows.map((r: any) => new Date(r.timestamp).getTime());
95	
96	                // Insert compressed archive row
97	                const { error: archiveErr } = await supabase
98	                    .from('fact_outcomes_archive')
99	                    .insert({
100	                        agent_id: first.agent_id,
101	                        action_id: first.action_id,
102	                        context_id: first.context_id,
103	                        customer_id: first.customer_id,
104	                        period_start: new Date(Math.min(...timestamps)).toISOString(),
105	                        period_end: new Date(Math.max(...timestamps)).toISOString(),
106	                        total_outcomes: totalOutcomes,
107	                        total_successes: totalSuccesses,
108	                        avg_response_time_ms: Math.round(avgResponseTime),
109	                        avg_success_rate: totalSuccesses / totalOutcomes,
110	                        compression_ratio: Math.min(totalOutcomes, COMPRESSION_RATIO),
111	                        sample_count: totalOutcomes,
112	                    });
113	
114	                if (archiveErr) {
115	                    console.error('[pruning] Archive insert failed:', archiveErr.message);
116	                    (results.stage1_archive as any).errors++;
117	                    continue;
118	                }
119	
120	                // Soft-delete the original rows (append-only table, so we mark is_deleted)
121	                // We use individual deletes since fact_outcomes is append-only
122	                // Actually, fact_outcomes has BEFORE UPDATE trigger that prevents updates
123	                // So we need to use a direct SQL approach via RPC or just skip deletion
124	                // For safety, we'll insert deletion markers instead
125	                // NOTE: Since fact_outcomes is APPEND-ONLY, we cannot UPDATE is_deleted.
126	                // Instead, we track archived outcome_ids and filter them in queries.
127	                // The scoring views already filter is_deleted=FALSE and is_synthetic=FALSE.
128	                // For actual deletion, we need to drop and recreate the trigger temporarily.
129	                // For now, log what WOULD be deleted:
130	                const outcomeIds = rows.map((r: any) => r.outcome_id);
131	                console.log(`[pruning] Archived ${totalOutcomes} rows for group. IDs: ${outcomeIds.length} rows`);
132	
133	                (results.stage1_archive as any).groups_archived++;
134	                (results.stage1_archive as any).rows_deleted += totalOutcomes;
135	            }
136	        } else {
137	            console.log('[pruning] Stage 1: No rows eligible for archiving');
138	        }
139	    } catch (err) {
140	        console.error('[pruning] Stage 1 error:', err);
141	        (results.stage1_archive as any).errors++;
142	    }
143	
144	    // ── Stage 2: Cold delete from archive ──────────────────────
145	    // Delete archive rows older than 365 days
146	    try {
147	        const coldCutoff = new Date(Date.now() - COLD_RETENTION_DAYS * 24 * 60 * 60 * 1000).toISOString();
148	
149	        const { data: oldArchive, error: coldQueryErr } = await supabase
150	            .from('fact_outcomes_archive')
151	            .select('archive_id')
152	            .lt('period_end', coldCutoff);
153	
154	        if (coldQueryErr) {
155	            console.error('[pruning] Stage 2 query failed:', coldQueryErr.message);
156	            (results.stage2_cold_delete as any).errors++;
157	        } else if (oldArchive && oldArchive.length > 0) {
158	            const archiveIds = oldArchive.map((r: any) => r.archive_id);
159	            const { error: deleteErr } = await supabase
160	                .from('fact_outcomes_archive')
161	                .delete()
162	                .in('archive_id', archiveIds);
163	
164	            if (deleteErr) {
165	                console.error('[pruning] Stage 2 delete failed:', deleteErr.message);
166	                (results.stage2_cold_delete as any).errors++;
167	            } else {
168	                (results.stage2_cold_delete as any).rows_deleted = archiveIds.length;
169	                console.log(`[pruning] Stage 2: Deleted ${archiveIds.length} archive rows older than ${COLD_RETENTION_DAYS} days`);
170	            }
171	        } else {
172	            console.log('[pruning] Stage 2: No archive rows eligible for cold deletion');
173	        }
174	    } catch (err) {
175	        console.error('[pruning] Stage 2 error:', err);
176	        (results.stage2_cold_delete as any).errors++;
177	    }
178	
179	    // ── Stage 3: Report salience stats ─────────────────────────
180	    try {
181	        const { count: totalHot } = await supabase
182	            .from('fact_outcomes')
183	            .select('outcome_id', { count: 'exact', head: true })
184	            .eq('is_deleted', false);
185	
186	        const { count: lowSalience } = await supabase
187	            .from('fact_outcomes')
188	            .select('outcome_id', { count: 'exact', head: true })
189	            .eq('is_deleted', false)
190	            .lt('salience_score', 0.01);
191	
192	        (results.stage3_stats as any).total_hot_rows = totalHot ?? 0;
193	        (results.stage3_stats as any).low_salience_rows = lowSalience ?? 0;
194	    } catch (err) {
195	        console.error('[pruning] Stage 3 stats error:', err);
196	    }
197	
198	    // ── Response ────────────────────────────────────────────────
199	    const duration = Date.now() - startTime;
200	    const response = {
201	        completed: true,
202	        duration_ms: duration,
203	        timestamp: new Date().toISOString(),
204	        retention: {
205	            hot_days: HOT_RETENTION_DAYS,
206	            cold_days: COLD_RETENTION_DAYS,
207	            compression_ratio: COMPRESSION_RATIO,
208	        },
209	        results,
210	    };
211	
212	    console.log('[pruning-scheduler] Result:', JSON.stringify(response));
213	
214	    return new Response(
215	        JSON.stringify(response),
216	        { status: 200, headers: { 'Content-Type': 'application/json' } }
217	    );
218	});
219

1	// @ts-nocheck — Deno runtime (not Node.js)
2	// ==============================================================
3	// LAYERINFINITE — Edge Function: notification-dispatcher
4	// ==============================================================
5	// Called by pg_cron every 2 minutes.
6	// Finds undelivered alerts for all active channels.
7	// Delivers each alert to its configured destination.
8	// Records delivery result in alert_notification_log.
9	// Never delivers the same alert to the same channel twice
10	// (enforced by UNIQUE constraint on log table).
11	//
12	// Deploy: supabase functions deploy notification-dispatcher
13	// Cron:   */2 * * * *  (every 2 minutes)
14	// ==============================================================
15	
16	import { createClient } from 'https://esm.sh/@supabase/supabase-js@2';
17	
18	const SUPABASE_URL = Deno.env.get('SUPABASE_URL')!;
19	const SUPABASE_SERVICE_ROLE_KEY = Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')!;
20	const LAYERINFINITE_INTERNAL_SECRET = Deno.env.get('LAYERINFINITE_INTERNAL_SECRET');
21	const RESEND_API_KEY = Deno.env.get('RESEND_API_KEY') ?? '';
22	const ALERT_FROM_EMAIL = Deno.env.get('ALERT_FROM_EMAIL') ?? 'alerts@layerinfinite.dev';
23	const DASHBOARD_URL = Deno.env.get('DASHBOARD_URL') ?? '';
24	
25	// ── Helpers ─────────────────────────────────────────────────
26	
27	function severityEmoji(severity: string): string {
28	    switch (severity) {
29	        case 'critical': return '🔴';
30	        case 'warning': return '🟡';
31	        case 'info': return '🔵';
32	        default: return '⚪';
33	    }
34	}
35	
36	const ALERT_TYPE_LABELS: Record<string, string> = {
37	    degradation: 'Degradation',
38	    score_flip: 'Score Flip',
39	    latency_spike: 'Latency Spike',
40	    context_drift: 'Context Drift',
41	    coordinated_failure: 'Coordinated Failure',
42	    silent_failure: 'Silent Failure',
43	};
44	
45	function alertTypeLabel(type: string): string {
46	    return ALERT_TYPE_LABELS[type] ?? type;
47	}
48	
49	function formatTimestamp(ts: string): string {
50	    return new Date(ts).toLocaleString('en-US', {
51	        timeZone: 'UTC',
52	        year: 'numeric',
53	        month: 'short',
54	        day: 'numeric',
