69	async function deliverSlack(
70	    destination: string,
71	    alert: Record<string, any>,
72	): Promise<DeliveryResult> {
73	    const payload = {
74	        blocks: [
75	            {
76	                type: 'header',
77	                text: {
78	                    type: 'plain_text',
79	                    text: `${severityEmoji(alert.severity)} Layerinfinite Alert: ${alertTypeLabel(alert.alert_type)}`,
80	                },
81	            },
82	            {
83	                type: 'section',
84	                text: {
85	                    type: 'mrkdwn',
86	                    text: alert.message ?? 'No message provided.',
87	                },
88	            },
89	            {
90	                type: 'context',
91	                elements: [
92	                    {
93	                        type: 'mrkdwn',
94	                        text: `*Severity:* ${alert.severity} | *Detected:* ${formatTimestamp(alert.detected_at)}`,
95	                    },
96	                ],
97	            },
98	        ],
99	    };
100	
101	    const response = await fetch(destination, {
102	        method: 'POST',
103	        headers: { 'Content-Type': 'application/json' },
104	        body: JSON.stringify(payload),
105	    });
106	
107	    return {
108	        ok: response.ok,
109	        status: response.status,
110	        error: response.ok ? null : `HTTP ${response.status}`,
111	    };
112	}
