191	            ${alertsLink ? `<p><a href="${alertsLink}" style="color: #3b82f6;">View alerts in dashboard</a></p>` : ''}
192	            ${settingsLink ? `<p style="font-size: 12px; color: #999;"><a href="${settingsLink}" style="color: #999;">Manage alert settings</a></p>` : ''}
