219	// ── Main handler ────────────────────────────────────────────
220	
221	Deno.serve(async (req: Request): Promise<Response> => {
222	    const startTime = Date.now();
223	
224	    // ── Auth check ─────────────────────────────────────────────
225	    const authHeader = req.headers.get('Authorization') ?? '';
226	    const isCronInvocation = req.headers.get('x-supabase-event') === 'cron';
227	
228	    if (!isCronInvocation && (!LAYERINFINITE_INTERNAL_SECRET || authHeader !== `Bearer ${LAYERINFINITE_INTERNAL_SECRET}`)) {
229	        return new Response(
230	            JSON.stringify({ error: 'Unauthorized' }),
231	            { status: 401, headers: { 'Content-Type': 'application/json' } },
232	        );
233	    }
234	
235	    const supabase = createClient(SUPABASE_URL, SUPABASE_SERVICE_ROLE_KEY, {
236	        auth: { persistSession: false },
237	    });
238	
239	    const results = {
240	        alerts_found: 0,
241	        delivered: 0,
242	        failed: 0,
243	        errors: [] as string[],
244	    };
245	
246	    // ── Check for test mode (single channel test) ──────────────
247	    let testMode = false;
248	    let testChannelId: string | null = null;
249	    let testAlert: Record<string, any> | null = null;
250	
251	    if (req.method === 'POST') {
252	        try {
253	            const body = await req.json();
254	            if (body.test === true && body.channel_id) {
255	                testMode = true;
256	                testChannelId = body.channel_id;
257	                testAlert = {
258	                    alert_id: '00000000-0000-0000-0000-000000000000',
259	                    alert_type: body.alert_type ?? 'latency_spike',
260	                    severity: body.severity ?? 'warning',
261	                    message: body.message ?? 'This is a test notification from Layerinfinite. Your alert channel is configured correctly.',
262	                    agent_id: null,
263	                    action_name: 'test_action',
264	                    metadata: { test: true },
265	                    detected_at: new Date().toISOString(),
266	                };
267	            }
268	        } catch {
269	            // Not JSON or missing fields — continue to normal mode
270	        }
271	    }
272	
273	    // ── Test mode: deliver to single channel ───────────────────
274	    if (testMode && testChannelId && testAlert) {
275	        const { data: channel, error: chErr } = await supabase
276	            .from('alert_notification_channels')
277	            .select('id, channel_type, destination, label, customer_id')
278	            .eq('id', testChannelId)
279	            .maybeSingle();
280	
281	        if (chErr || !channel) {
282	            return new Response(
283	                JSON.stringify({ success: false, error: 'Channel not found' }),
284	                { status: 404, headers: { 'Content-Type': 'application/json' } },
285	            );
286	        }
287	
288	        let result: DeliveryResult;
289	        if (channel.channel_type === 'slack_webhook') {
290	            result = await deliverSlack(channel.destination, testAlert);
291	        } else if (channel.channel_type === 'webhook') {
292	            result = await deliverWebhook(channel.destination, testAlert);
293	        } else {
294	            result = await deliverEmail(channel.destination, testAlert);
295	        }
296	
297	        return new Response(
298	            JSON.stringify({ success: result.ok, error: result.error, http_status: result.status }),
299	            { status: result.ok ? 200 : 502, headers: { 'Content-Type': 'application/json' } },
300	        );
301	    }
302	
303	    // ── Normal mode: find undelivered alerts ───────────────────
304	    const { data: pending, error: queryErr } = await supabase.rpc(
305	        'get_undelivered_alerts',
306	    ).catch(() => ({ data: null, error: { message: 'RPC not found, using fallback query' } }));
307	
308	    // Fallback: raw query if RPC doesn't exist
309	    let rows: Record<string, any>[] = [];
310	
311	    if (queryErr || !pending) {
312	        // Use a simpler approach: fetch active channels, then match alerts
313	        const { data: channels } = await supabase
314	            .from('alert_notification_channels')
315	            .select('id, channel_type, destination, label, customer_id, min_severity, alert_type_filter')
316	            .eq('is_active', true);
317	
318	        if (!channels || channels.length === 0) {
319	            console.log('[notification-dispatcher] No active channels found');
320	            return new Response(
321	                JSON.stringify({ ...results, duration_ms: Date.now() - startTime }),
322	                { status: 200, headers: { 'Content-Type': 'application/json' } },
323	            );
324	        }
325	
326	        const cutoff = new Date(Date.now() - 24 * 60 * 60 * 1000).toISOString();
327	
328	        for (const ch of channels) {
329	            // Get alerts for this channel's customer
330	            const { data: alerts } = await supabase
331	                .from('degradation_alert_events')
332	                .select('alert_id, alert_type, severity, message, agent_id, action_name, metadata, detected_at')
333	                .gte('detected_at', cutoff)
334	                .order('detected_at', { ascending: true })
335	                .limit(100);
336	
337	            if (!alerts || alerts.length === 0) continue;
338	
339	            // Filter by customer's agents
340	            const { data: agentIds } = await supabase
341	                .from('dim_agents')
342	                .select('agent_id')
343	                .eq('customer_id', ch.customer_id);
344	
345	            const customerAgentIds = new Set((agentIds ?? []).map((a: any) => a.agent_id));
346	
347	            // Get already-delivered alert IDs for this channel
348	            const { data: delivered } = await supabase
349	                .from('alert_notification_log')
350	                .select('alert_id')
351	                .eq('channel_id', ch.id);
352	
353	            const deliveredIds = new Set((delivered ?? []).map((d: any) => d.alert_id));
354	
355	            const sevOrder: Record<string, number> = { info: 0, warning: 1, critical: 2 };
356	            const minSevLevel = sevOrder[ch.min_severity] ?? 1;
357	
358	            for (const alert of alerts) {
359	                // Skip if already delivered
360	                if (deliveredIds.has(alert.alert_id)) continue;
361	
362	                // Skip if agent doesn't belong to customer (null agent_id = system alert, include it)
363	                if (alert.agent_id && !customerAgentIds.has(alert.agent_id)) continue;
364	
365	                // Severity filter
366	                const alertSevLevel = sevOrder[alert.severity] ?? 0;
367	                if (alertSevLevel < minSevLevel) continue;
368	
369	                // Type filter (empty = all)
370	                if (ch.alert_type_filter && ch.alert_type_filter.length > 0) {
371	                    if (!ch.alert_type_filter.includes(alert.alert_type)) continue;
372	                }
373	
374	                rows.push({
375	                    channel_id: ch.id,
376	                    channel_type: ch.channel_type,
377	                    destination: ch.destination,
378	                    label: ch.label,
379	                    customer_id: ch.customer_id,
380	                    ...alert,
381	                });
382	            }
383	        }
384	    } else {
385	        rows = pending as Record<string, any>[];
386	    }
387	
388	    // Cap at 100 per run
389	    rows = rows.slice(0, 100);
390	    results.alerts_found = rows.length;
391	
392	    console.log(`[notification-dispatcher] Found ${rows.length} undelivered alerts`);
393	
394	    // ── Deliver each alert ─────────────────────────────────────
395	    for (const row of rows) {
396	        try {
397	            let result: DeliveryResult;
398	
399	            if (row.channel_type === 'slack_webhook') {
400	                result = await deliverSlack(row.destination, row);
401	            } else if (row.channel_type === 'webhook') {
402	                result = await deliverWebhook(row.destination, row);
403	            } else if (row.channel_type === 'email') {
404	                result = await deliverEmail(row.destination, row);
405	            } else {
406	                result = { ok: false, status: null, error: `Unknown channel type: ${row.channel_type}` };
407	            }
408	
409	            // Write to log REGARDLESS of success (prevents retry loops)
410	            await supabase
411	                .from('alert_notification_log')
412	                .upsert(
413	                    {
414	                        channel_id: row.channel_id,
415	                        alert_id: row.alert_id,
416	                        success: result.ok,
417	                        error_message: result.error,
418	                        http_status: result.status,
419	                    },
420	                    { onConflict: 'channel_id,alert_id' },
421	                );
422	
423	            // Update last delivery stats on channel
424	            await supabase
425	                .from('alert_notification_channels')
426	                .update({
427	                    last_delivery_at: new Date().toISOString(),
428	                    last_delivery_ok: result.ok,
429	                    last_delivery_error: result.error,
430	                })
431	                .eq('id', row.channel_id);
432	
433	            if (result.ok) {
434	                results.delivered++;
435	            } else {
436	                results.failed++;
437	                results.errors.push(`${row.channel_type}:${row.alert_id}: ${result.error}`);
438	            }
439	        } catch (err) {
440	            console.error('[notification-dispatcher] Delivery error:', err);
441	            results.failed++;
442	
443	            // Still write to log so we don't retry infinitely
444	            try {
445	                await supabase
446	                    .from('alert_notification_log')
447	                    .upsert(
448	                        {
449	                            channel_id: row.channel_id,
450	                            alert_id: row.alert_id,
451	                            success: false,
452	                            error_message: String(err).slice(0, 500),
453	                            http_status: null,
454	                        },
455	                        { onConflict: 'channel_id,alert_id' },
456	                    );
457	            } catch {
458	                // Last resort — can't even log the failure
459	                console.error('[notification-dispatcher] Failed to log delivery failure');
460	            }
461	        }
462	    }
463	
464	    const duration = Date.now() - startTime;
465	    console.log(`[notification-dispatcher] Done in ${duration}ms: ${results.delivered} delivered, ${results.failed} failed`);
466	
467	    return new Response(
468	        JSON.stringify({ ...results, duration_ms: duration }),
469	        { status: 200, headers: { 'Content-Type': 'application/json' } },
470	    );
471	});
