1	/**
2	 * Layerinfinite — deploy.js
3	 * Generic deployer: runs a specific set of migration files
4	 * against the live Supabase database.
5	 *
6	 * Usage:
7	 *   node scripts/deploy.js phase1      ← runs 001,002,003,005,006 + seed + test
8	 *   node scripts/deploy.js phase2      ← runs 004,009,010 + test
9	 *   node scripts/deploy.js all         ← runs everything
10	 *   node scripts/deploy.js sql <file>  ← runs a single SQL file
11	 */
12	
13	const { Client } = require('pg');
14	const fs = require('fs');
15	const path = require('path');
16	require('dotenv').config();
17	
18	const DB_URL = process.env.DB_URL;
19	if (!DB_URL) {
20	    console.error('ERROR: DB_URL not set in .env');
21	    process.exit(1);
22	}
23	
24	const MIGRATIONS = path.join(__dirname, '..', 'supabase', 'migrations');
25	const SEED = path.join(__dirname, '..', 'supabase', 'seed');
26	const TESTS = path.join(__dirname, '..', 'tests');
27	
28	const PHASE_MAP = {
29	    phase1: [
30	        `${MIGRATIONS}/001_create_dimensions.sql`,
31	        `${MIGRATIONS}/002_create_fact_outcomes.sql`,
32	        `${MIGRATIONS}/003_create_episodes.sql`,
33	        `${MIGRATIONS}/005_create_indexes.sql`,
34	        `${MIGRATIONS}/006_create_rls_policies.sql`,
35	        `${SEED}/cold_start_priors.sql`,
36	        `${TESTS}/layer1/test_gate.sql`,
37	    ],
38	    phase2: [
39	        `${MIGRATIONS}/004_create_materialized_views.sql`,
40	        `${MIGRATIONS}/009_add_matview_unique_indexes.sql`,
41	        `${MIGRATIONS}/010_create_helper_functions.sql`,
42	        `${TESTS}/layer2/test_gate.sql`,
43	    ],
44	    all: null,  // filled below
45	};
46	
47	// Build 'all' from sorted migrations + seeds + tests
48	const allMigrations = fs.readdirSync(MIGRATIONS).filter(f => f.endsWith('.sql')).sort()
49	    .map(f => `${MIGRATIONS}/${f}`);
50	PHASE_MAP.all = [...allMigrations, `${SEED}/cold_start_priors.sql`];
51	
52	let passCount = 0;
53	let failCount = 0;
54	
55	async function runSql(client, filePath, label) {
56	    const sql = fs.readFileSync(filePath, 'utf-8');
57	    const short = path.basename(filePath);
58	    try {
59	        await client.query(sql);
60	        console.log(`  ✅  ${short}`);
61	        passCount++;
62	        return true;
63	    } catch (err) {
64	        const msg = err.message || '';
65	        if (msg.includes('already exists') || msg.includes('duplicate')) {
66	            console.log(`  ⚠️   ${short} — already exists (OK)`);
67	            passCount++;
68	            return true;
69	        }
70	        console.error(`  ❌  ${short}`);
71	        console.error(`       ↳ ${err.message}`);
72	        if (err.detail) console.error(`       ↳ Detail: ${err.detail}`);
73	        if (err.hint) console.error(`       ↳ Hint:   ${err.hint}`);
74	        failCount++;
75	        return false;
76	    }
77	}
78	
79	async function main() {
80	    const args = process.argv.slice(2);
81	    const target = args[0] || 'phase2';
82	    const sqlFile = args[1];
83	
84	    console.log('\n═══════════════════════════════════════════════════');
85	    console.log(`  LAYERINFINITE — Deploy: ${target.toUpperCase()}`);
86	    console.log('═══════════════════════════════════════════════════\n');
87	
88	    const client = new Client({ connectionString: DB_URL, ssl: { rejectUnauthorized: false } });
89	
90	    console.log('🔌 Connecting...');
91	    await client.connect();
92	    const { rows } = await client.query('SELECT version()');
93	    console.log(`✅ Connected — ${rows[0].version.split(' ').slice(0, 2).join(' ')}\n`);
94	
95	    let files = [];
96	
97	    if (target === 'sql' && sqlFile) {
98	        files = [path.resolve(sqlFile)];
99	    } else if (PHASE_MAP[target]) {
100	        files = PHASE_MAP[target];
101	    } else {
102	        console.error(`Unknown target: ${target}. Use: phase1, phase2, all, sql <file>`);
103	        process.exit(1);
104	    }
105	
106	    console.log(`Running ${files.length} file(s):\n`);
107	    for (const f of files) {
108	        await runSql(client, f, path.basename(f));
109	    }
110	
111	    await client.end();
112	
113	    console.log('\n═══════════════════════════════════════════════════');
114	    if (failCount === 0) {
115	        console.log(`  ✅ ${target.toUpperCase()} DEPLOYED — ${passCount} steps passed\n`);
116	        console.log(`  git commit -m "feat: layer-${target.replace('phase', '')}-complete"`);
117	    } else {
118	        console.error(`  ❌ ${failCount} step(s) FAILED — see errors above`);
119	        process.exit(1);
120	    }
121	    console.log('═══════════════════════════════════════════════════\n');
122	}
123	
124	main().catch(err => {
125	    console.error('Fatal:', err.message);
126	    process.exit(1);
127	});
