3	const dns = require('node:dns').promises;
4	
5	function parseUrlList(raw) {
6	    return String(raw || '')
7	        .split(',')
8	        .map((s) => s.trim())
9	        .filter(Boolean);
10	}
11	
12	function normalizeOrigin(value) {
13	    try {
14	        const url = new URL(value);
15	        return url.origin;
16	    } catch {
17	        return null;
18	    }
19	}
20	
21	async function resolveHost(hostname) {
22	    try {
23	        const records = await dns.lookup(hostname, { all: true });
24	        const ips = [...new Set(records.map((r) => r.address))].sort();
25	        return { ok: ips.length > 0, ips, error: null };
26	    } catch (err) {
27	        return { ok: false, ips: [], error: err instanceof Error ? err.message : String(err) };
28	    }
29	}
30	
31	async function main() {
32	    const primary = process.env.PRIMARY_API_URL || process.env.LAYERINFINITE_BASE_URL || '';
33	    const fallbacksRaw = process.env.FALLBACK_API_URLS || process.env.LAYERINFINITE_BASE_URLS || '';
34	    const fallbackList = parseUrlList(fallbacksRaw);
35	
36	    const failures = [];
37	    const warnings = [];
38	
39	    if (!primary) {
40	        failures.push('PRIMARY_API_URL (or LAYERINFINITE_BASE_URL) is required.');
41	    }
42	
43	    const origins = [];
44	    if (primary) origins.push(primary);
45	    origins.push(...fallbackList);
46	
47	    const normalized = origins
48	        .map((u) => ({ raw: u, origin: normalizeOrigin(u) }))
49	        .filter((u) => u.origin !== null);
50	
51	    if (normalized.length !== origins.length) {
52	        failures.push('One or more endpoint URLs are invalid. Use full https URLs.');
53	    }
54	
55	    const uniqueOrigins = [...new Set(normalized.map((u) => u.origin))];
56	
57	    if (uniqueOrigins.length < 2) {
58	        failures.push('At least 2 unique endpoint origins are required (primary + at least one independent fallback).');
59	    }
60	
61	    for (const origin of uniqueOrigins) {
62	        const parsed = new URL(origin);
63	        if (parsed.protocol !== 'https:') {
64	            failures.push(`Endpoint must use https: ${origin}`);
65	        }
66	    }
67	
68	    if (uniqueOrigins.length > 0) {
69	        const primaryOrigin = normalizeOrigin(primary);
70	        const duplicateFallback = fallbackList.some((f) => normalizeOrigin(f) === primaryOrigin);
71	        if (duplicateFallback) {
72	            failures.push('Fallback list includes the same origin as primary endpoint.');
73	        }
74	    }
75	
76	    const dnsInfo = {};
77	    for (const origin of uniqueOrigins) {
78	        const host = new URL(origin).hostname;
79	        dnsInfo[origin] = await resolveHost(host);
80	        if (!dnsInfo[origin].ok) {
81	            failures.push(`DNS resolution failed for ${origin}: ${dnsInfo[origin].error}`);
82	        }
83	    }
84	
85	    const ipSets = uniqueOrigins
86	        .map((origin) => ({ origin, ips: dnsInfo[origin]?.ips || [] }))
87	        .filter((r) => r.ips.length > 0)
88	        .map((r) => r.ips.join(','));
89	
90	    if (ipSets.length >= 2) {
91	        const allSameIpSet = ipSets.every((value) => value === ipSets[0]);
92	        if (allSameIpSet) {
93	            warnings.push('All endpoints currently resolve to identical IP sets. This may indicate shared infrastructure.');
94	        }
95	    }
96	
97	    console.log('=== Endpoint Independence Check ===');
98	    console.log('Primary:', primary || '(missing)');
99	    console.log('Fallbacks:', fallbackList.length ? fallbackList.join(', ') : '(none)');
100	    console.log('Unique origins:', uniqueOrigins.join(', ') || '(none)');
101	    console.log('');
102	
103	    for (const origin of uniqueOrigins) {
104	        const item = dnsInfo[origin];
105	        if (!item) continue;
106	        if (item.ok) {
107	            console.log(`- ${origin} -> ${item.ips.join(', ')}`);
108	        } else {
109	            console.log(`- ${origin} -> DNS ERROR: ${item.error}`);
110	        }
111	    }
112	
113	    if (warnings.length) {
114	        console.log('\nWarnings:');
115	        for (const warning of warnings) {
116	            console.log(`- ${warning}`);
117	        }
118	    }
119	
120	    if (failures.length) {
121	        console.error('\nFailures:');
122	        for (const failure of failures) {
123	            console.error(`- ${failure}`);
124	        }
125	        process.exit(1);
126	    }
127	
128	    if (warnings.length) {
129	        console.log('\nResult: PASS WITH WARNINGS');
130	    } else {
131	        console.log('\nResult: PASS');
132	    }
133	}
134	
135	main().catch((err) => {
136	    console.error('Unexpected error:', err instanceof Error ? err.message : String(err));
137	    process.exit(1);
138	});
