3	function parseUrlList(raw) {
4	    return String(raw || '')
5	        .split(',')
6	        .map((s) => s.trim())
7	        .filter(Boolean);
8	}
9	
10	function normalizeOrigin(value) {
11	    return new URL(value).origin;
12	}
