14	async function fetchWithTimeout(url, timeoutMs) {
15	    const controller = new AbortController();
16	    const timer = setTimeout(() => controller.abort(), timeoutMs);
17	    try {
18	        const res = await fetch(url, {
19	            signal: controller.signal,
20	            headers: { Accept: 'application/json' },
21	        });
22	        return { ok: true, status: res.status, bodyText: await res.text() };
23	    } catch (err) {
24	        return {
25	            ok: false,
26	            status: 0,
27	            bodyText: '',
28	            error: err instanceof Error ? err.message : String(err),
29	        };
30	    } finally {
31	        clearTimeout(timer);
32	    }
33	}
