35	async function probePath(path, endpoints, timeoutMs) {
36	    const attempts = [];
37	    for (let i = 0; i < endpoints.length; i += 1) {
38	        const endpoint = endpoints[i];
39	        const url = `${endpoint}${path.startsWith('/') ? path : `/${path}`}`;
40	        const result = await fetchWithTimeout(url, timeoutMs);
41	
42	        attempts.push({ endpoint, url, ...result });
43	
44	        if (!result.ok) {
45	            continue;
46	        }
47	
48	        if (result.status >= 500) {
49	            continue;
50	        }
51	
52	        return {
53	            recovered: i > 0,
54	            endpoint,
55	            status: result.status,
56	            attempts,
57	        };
58	    }
59	
60	    return {
61	        recovered: false,
62	        endpoint: null,
63	        status: 0,
64	        attempts,
65	    };
66	}
67	
68	async function main() {
69	    const fallbackRaw = process.env.DRILL_FALLBACK_URLS || process.env.FALLBACK_API_URLS || process.env.LAYERINFINITE_BASE_URLS || '';
70	    const configuredPrimary = process.env.DRILL_PRIMARY_URL || process.env.PRIMARY_API_URL || process.env.LAYERINFINITE_BASE_URL || '';
71	    const timeoutMs = Number.parseInt(process.env.DRILL_TIMEOUT_MS || '10000', 10);
72	    const forcePrimaryDown = (process.env.DRILL_FORCE_PRIMARY_DOWN || 'true').toLowerCase() !== 'false';
73	
74	    const fallbacks = parseUrlList(fallbackRaw).map((u) => normalizeOrigin(u));
75	    if (fallbacks.length === 0) {
76	        console.error('DRILL_FALLBACK_URLS (or FALLBACK_API_URLS/LAYERINFINITE_BASE_URLS) must include at least one fallback endpoint.');
77	        process.exit(1);
78	    }
79	
80	    const primaryOrigin = configuredPrimary ? normalizeOrigin(configuredPrimary) : null;
81	    const simulatedPrimary = forcePrimaryDown
82	        ? 'https://primary-failover-drill.invalid'
83	        : (primaryOrigin || fallbacks[0]);
84	
85	    const endpoints = [simulatedPrimary, ...fallbacks].filter((v, idx, arr) => arr.indexOf(v) === idx);
86	    const probePaths = ['/health', '/health/deep'];
87	
88	    console.log('=== Failover Drill ===');
89	    console.log('Primary (simulated):', simulatedPrimary);
90	    console.log('Fallbacks:', fallbacks.join(', '));
91	    console.log('Probe paths:', probePaths.join(', '));
92	
93	    let recoveredCount = 0;
94	    const failures = [];
95	
96	    for (const path of probePaths) {
97	        const result = await probePath(path, endpoints, timeoutMs);
98	
99	        console.log(`\nPath ${path}:`);
100	        for (const attempt of result.attempts) {
101	            if (!attempt.ok) {
102	                console.log(`- ${attempt.endpoint} -> NETWORK ERROR (${attempt.error})`);
103	            } else {
104	                console.log(`- ${attempt.endpoint} -> HTTP ${attempt.status}`);
105	            }
106	        }
107	
108	        if (!result.endpoint) {
109	            failures.push(`No endpoint succeeded for ${path}`);
110	            continue;
111	        }
112	
113	        const endpointLabel = result.recovered ? `${result.endpoint} (recovered via fallback)` : result.endpoint;
114	        console.log(`=> SUCCESS via ${endpointLabel}`);
115	
116	        if (result.recovered) {
117	            recoveredCount += 1;
118	        }
119	    }
120	
121	    if (failures.length) {
122	        console.error('\nFailures:');
123	        for (const failure of failures) {
124	            console.error(`- ${failure}`);
125	        }
126	        process.exit(1);
127	    }
128	
129	    if (forcePrimaryDown && recoveredCount === 0) {
130	        console.error('\nFailure: drill expected fallback recovery, but no fallback switchover was observed.');
131	        process.exit(1);
132	    }
133	
134	    console.log(`\nResult: PASS (fallback recoveries observed: ${recoveredCount})`);
135	}
136	
137	main().catch((err) => {
138	    console.error('Unexpected error:', err instanceof Error ? err.message : String(err));
139	    process.exit(1);
140	});
