3	/**
4	 * Cohort persistence deployment verification.
5	 *
6	 * Checks each configured environment for:
7	 *  1) recommendation_cohort_cycles table exists
8	 *  2) upsert_recommendation_cohort_cycle RPC exists
9	 *
10	 * Exit code:
11	 *  - 0: all environments pass
12	 *  - 1: any environment fails or config is invalid
13	 *
14	 * Configuration options:
15	 *
16	 * A) Multi-env via names:
17	 *    COHORT_ENVIRONMENTS=dev,staging,prod
18	 *    DEV_SUPABASE_URL=...
19	 *    DEV_SUPABASE_SERVICE_ROLE_KEY=...
20	 *    STAGING_SUPABASE_URL=...
21	 *    STAGING_SUPABASE_SERVICE_ROLE_KEY=...
22	 *    PROD_SUPABASE_URL=...
23	 *    PROD_SUPABASE_SERVICE_ROLE_KEY=...
24	 *
25	 * B) Multi-env via JSON:
26	 *    COHORT_ENVS_JSON='[{"name":"prod","url":"...","serviceRoleKey":"..."}]'
27	 *
28	 * C) Single env fallback:
29	 *    SUPABASE_URL=...
30	 *    SUPABASE_SERVICE_ROLE_KEY=...
31	 */
32	
33	function parseEnvNameList(raw) {
34	    return String(raw || '')
35	        .split(',')
36	        .map((v) => v.trim())
37	        .filter(Boolean);
38	}
39	
40	function maskKey(value) {
41	    const raw = String(value || '');
42	    if (raw.length <= 8) return '***';
43	    return `${raw.slice(0, 4)}...${raw.slice(-4)}`;
44	}
45	
46	function normalizeName(name) {
47	    return name.trim().toUpperCase().replace(/[^A-Z0-9]/g, '_');
48	}
49	
50	function loadTargetsFromJson(rawJson) {
51	    const parsed = JSON.parse(rawJson);
52	    if (!Array.isArray(parsed)) {
53	        throw new Error('COHORT_ENVS_JSON must be a JSON array');
54	    }
55	
56	    return parsed.map((entry, idx) => {
57	        const name = String(entry?.name || `env_${idx + 1}`);
58	        const url = String(entry?.url || '').trim();
59	        const serviceRoleKey = String(entry?.serviceRoleKey || '').trim();
60	        return { name, url, serviceRoleKey };
61	    });
62	}
63	
64	function loadTargetsFromNamedVars(rawNames) {
65	    const names = parseEnvNameList(rawNames);
66	    return names.map((name) => {
67	        const normalized = normalizeName(name);
68	        const url = process.env[`${normalized}_SUPABASE_URL`] || '';
69	        const serviceRoleKey = process.env[`${normalized}_SUPABASE_SERVICE_ROLE_KEY`] || '';
70	        return { name, url: String(url).trim(), serviceRoleKey: String(serviceRoleKey).trim() };
71	    });
72	}
