74	function loadSingleTarget() {
75	    const url = String(process.env.SUPABASE_URL || '').trim();
76	    const serviceRoleKey = String(process.env.SUPABASE_SERVICE_ROLE_KEY || '').trim();
77	    return [{ name: process.env.COHORT_ENV_NAME || 'default', url, serviceRoleKey }];
78	}
79	
80	function loadTargets() {
81	    const jsonRaw = process.env.COHORT_ENVS_JSON;
82	    if (jsonRaw && String(jsonRaw).trim().length > 0) {
83	        return loadTargetsFromJson(String(jsonRaw));
84	    }
85	
86	    const namedRaw = process.env.COHORT_ENVIRONMENTS;
87	    if (namedRaw && String(namedRaw).trim().length > 0) {
88	        return loadTargetsFromNamedVars(String(namedRaw));
89	    }
90	
91	    return loadSingleTarget();
92	}
