94	function isMissingTableError(error) {
95	    const code = String(error?.code || '');
96	    const msg = String(error?.message || '').toLowerCase();
97	    return (
98	        code === '42P01' ||
99	        code === 'PGRST205' ||
100	        (msg.includes('relation') && msg.includes('recommendation_cohort_cycles'))
101	    );
102	}
103	
104	function isMissingRpcError(error) {
105	    const code = String(error?.code || '');
106	    const msg = String(error?.message || '').toLowerCase();
107	
108	    return (
109	        code === '42883' ||
110	        code === 'PGRST202' ||
111	        (msg.includes('could not find the function') && msg.includes('upsert_recommendation_cohort_cycle')) ||
112	        (msg.includes('function') && msg.includes('upsert_recommendation_cohort_cycle') && msg.includes('does not exist'))
113	    );
114	}
115	
116	function isAuthError(error) {
117	    const code = String(error?.code || '').toUpperCase();
118	    const msg = String(error?.message || '').toLowerCase();
119	    const hint = String(error?.hint || '').toLowerCase();
120	
121	    return (
122	        code === '401' ||
123	        code === '403' ||
124	        code === 'PGRST301' ||
125	        msg.includes('invalid api key') ||
126	        msg.includes('invalid jwt') ||
127	        msg.includes('jwt') ||
128	        msg.includes('unauthorized') ||
129	        msg.includes('forbidden') ||
130	        hint.includes('service_role')
131	    );
132	}
133	
134	function summarizeError(error) {
135	    if (!error || typeof error !== 'object') {
136	        return 'unknown error';
137	    }
138	
139	    const parts = [error.code, error.message, error.hint, error.details]
140	        .map((v) => (v == null ? '' : String(v).trim()))
141	        .filter(Boolean);
142	
143	    if (parts.length > 0) {
144	        return parts.join(' | ');
145	    }
146	
147	    return 'unknown error';
148	}
149	
150	function withRestBase(url) {
151	    return String(url || '').replace(/\/+$/, '');
152	}
153	
154	function createRestHeaders(serviceRoleKey) {
155	    return {
156	        apikey: serviceRoleKey,
157	        Authorization: `Bearer ${serviceRoleKey}`,
158	        'Content-Type': 'application/json',
159	    };
160	}
