162	async function fetchWithTimeout(url, options, timeoutMs = 15000) {
163	    const controller = new AbortController();
164	    const timer = setTimeout(() => controller.abort(), timeoutMs);
165	    try {
166	        return await fetch(url, { ...options, signal: controller.signal });
167	    } finally {
168	        clearTimeout(timer);
169	    }
170	}
