184	function toProbeError(status, payload) {
185	    if (payload && typeof payload === 'object') {
186	        const code = payload.code != null ? String(payload.code) : String(status || '');
187	        const message = payload.message != null ? String(payload.message) : `HTTP ${status}`;
188	        const hint = payload.hint != null ? String(payload.hint) : '';
189	        const details = payload.details != null ? String(payload.details) : '';
190	        return { code, message, hint, details };
191	    }
192	    return { code: String(status || ''), message: `HTTP ${status}` };
193	}
