195	async function checkTable(target) {
196	    const baseUrl = withRestBase(target.url);
197	    const endpoint = `${baseUrl}/rest/v1/recommendation_cohort_cycles?select=cycle_id&limit=1`;
198	
199	    const response = await fetchWithTimeout(endpoint, {
200	        method: 'GET',
201	        headers: createRestHeaders(target.serviceRoleKey),
202	    });
203	
204	    if (response.ok) {
205	        return { ok: true, detail: 'table exists' };
206	    }
207	
208	    const payload = await readJsonSafe(response);
209	    const error = toProbeError(response.status, payload);
210	
211	    if (isAuthError(error)) {
212	        return { ok: false, detail: `table probe auth/config error: ${summarizeError(error)}` };
213	    }
214	
215	    if (isMissingTableError(error)) {
216	        return { ok: false, detail: `table missing (${error.code || 'unknown'})` };
217	    }
218	
219	    return { ok: false, detail: `table probe failed: ${summarizeError(error)}` };
220	}
