222	async function checkRpc(target) {
223	    const payload = {
224	        // Null customer forces an early validation error in the function body,
225	        // proving the RPC exists without creating any rows.
226	        p_customer_id: null,
227	        p_task_name: '__cohort_deploy_check__',
228	        p_observed_at: new Date().toISOString(),
229	        p_total_outcomes: 0,
230	        p_median_confidence: null,
231	        p_median_success_rate: null,
232	    };
233	
234	    const baseUrl = withRestBase(target.url);
235	    const endpoint = `${baseUrl}/rest/v1/rpc/upsert_recommendation_cohort_cycle`;
236	
237	    const response = await fetchWithTimeout(endpoint, {
238	        method: 'POST',
239	        headers: createRestHeaders(target.serviceRoleKey),
240	        body: JSON.stringify(payload),
241	    });
242	
243	    if (response.ok) {
244	        return { ok: true, detail: 'rpc exists (call succeeded)' };
245	    }
246	
247	    const body = await readJsonSafe(response);
248	    const error = toProbeError(response.status, body);
249	
250	    if (isAuthError(error)) {
251	        return { ok: false, detail: `rpc probe auth/config error: ${summarizeError(error)}` };
252	    }
253	
254	    if (isMissingRpcError(error)) {
255	        return { ok: false, detail: `rpc missing (${error.code || 'unknown'})` };
256	    }
257	
258	    if (!error.message && !error.code) {
259	        return { ok: false, detail: 'rpc probe failed: unknown error' };
260	    }
261	
262	    // Any non-missing-function DB error still proves function existence.
263	    return { ok: true, detail: `rpc exists (returned ${summarizeError(error)})` };
264	}
