266	function validateTargets(targets) {
267	    const issues = [];
268	
269	    if (!targets.length) {
270	        issues.push('No targets configured. Set COHORT_ENVIRONMENTS or SUPABASE_URL/SUPABASE_SERVICE_ROLE_KEY.');
271	        return issues;
272	    }
273	
274	    targets.forEach((t, idx) => {
275	        if (!t.url) {
