277	        }
278	        if (!t.serviceRoleKey) {
279	            issues.push(`Target[${idx}] ${t.name}: missing service role key`);
280	        }
281	        if (t.url) {
282	            try {
283	                const u = new URL(t.url);
284	                if (u.protocol !== 'https:') {
285	                    issues.push(`Target[${idx}] ${t.name}: URL must use https`);
286	                }
287	            } catch {
288	                issues.push(`Target[${idx}] ${t.name}: URL is invalid`);
289	            }
290	        }
291	    });
292	
293	    return issues;
294	}
