296	async function runTarget(target) {
297	    const [tableCheck, rpcCheck] = await Promise.all([
298	        checkTable(target),
299	        checkRpc(target),
300	    ]);
301	
302	    return {
303	        target,
304	        tableCheck,
305	        rpcCheck,
306	        ok: tableCheck.ok && rpcCheck.ok,
307	    };
308	}
309	
310	async function main() {
311	    const targets = loadTargets();
312	    const configIssues = validateTargets(targets);
313	
314	    if (configIssues.length > 0) {
315	        console.error('Configuration errors:');
316	        for (const issue of configIssues) {
317	            console.error(`- ${issue}`);
318	        }
319	        return 1;
320	    }
321	
322	    console.log('=== Cohort Persistence Deployment Check ===');
323	    console.log(`Targets: ${targets.map((t) => t.name).join(', ')}`);
324	
325	    const results = [];
326	    for (const target of targets) {
