78	async function requestWithTimeout({ url, method, headers, timeoutMs }) {
79	    const controller = new AbortController();
80	    const timer = setTimeout(() => controller.abort(), timeoutMs);
81	
82	    try {
83	        return await fetch(url, {
84	            method,
85	            headers,
86	            signal: controller.signal,
87	        });
88	    } finally {
89	        clearTimeout(timer);
90	    }
91	}
