93	async function queryCount({ supabaseUrl, serviceRoleKey, table, filters, timeoutMs }) {
94	    const url = buildRestUrl({
95	        supabaseUrl,
96	        table,
97	        params: {
98	            select: '*',
99	            ...filters,
100	        },
101	    });
102	
103	    const headResponse = await requestWithTimeout({
104	        url,
105	        method: 'HEAD',
106	        headers: buildServiceHeaders(serviceRoleKey, true),
107	        timeoutMs,
108	    });
109	
110	    if (!headResponse.ok) {
111	        throw new Error(`HEAD ${table} failed (${headResponse.status})`);
112	    }
113	
114	    const headerCount = parseContentRangeCount(headResponse.headers.get('content-range'));
115	    if (headerCount !== null) {
116	        return headerCount;
117	    }
118	
119	    const getResponse = await requestWithTimeout({
120	        url,
121	        method: 'GET',
122	        headers: buildServiceHeaders(serviceRoleKey, true),
123	        timeoutMs,
124	    });
125	
126	    const raw = await getResponse.text();
127	    let payload;
128	    try {
129	        payload = raw ? JSON.parse(raw) : [];
130	    } catch {
131	        payload = [];
132	    }
133	
134	    if (!getResponse.ok) {
135	        throw new Error(`GET ${table} failed (${getResponse.status}): ${JSON.stringify(payload)}`);
136	    }
137	
138	    const fallbackHeaderCount = parseContentRangeCount(getResponse.headers.get('content-range'));
139	    if (fallbackHeaderCount !== null) {
140	        return fallbackHeaderCount;
141	    }
142	
143	    return Array.isArray(payload) ? payload.length : 0;
144	}
