58	    if (/count\(\*\)::numeric \/ nullif\(count\(\*\) \+ 10, 0\)/.test(compact)) {
59	        return 10;
60	    }
61	    if (/count\(\*\)::numeric \/ nullif\(count\(\*\) \+ 5, 0\)/.test(compact)) {
