23	const headers = {
24	    apikey: SERVICE_KEY,
25	    Authorization: `Bearer ${SERVICE_KEY}`,
26	    'Content-Type': 'application/json',
27	};
28	
29	function toVectorLiteral(value) {
30	    if (Array.isArray(value)) {
31	        return `[${value.join(',')}]`;
32	    }
33	
34	    if (typeof value === 'string') {
35	        const trimmed = value.trim();
36	        if (trimmed.startsWith('[') && trimmed.endsWith(']')) {
37	            return trimmed;
38	        }
39	
40	        try {
41	            const parsed = JSON.parse(trimmed);
42	            if (Array.isArray(parsed)) {
43	                return `[${parsed.join(',')}]`;
44	            }
45	        } catch {
46	            // ignore parse failure
47	        }
48	    }
49	
50	    return null;
51	}
52	
53	function vectorDimensionFromLiteral(literal) {
54	    if (!literal) return 0;
55	    const inner = literal.trim().replace(/^\[/, '').replace(/\]$/, '').trim();
56	    if (!inner) return 0;
57	    return inner.split(',').length;
58	}
