60	async function restGet(pathAndQuery) {
61	    const url = `${SUPABASE_URL}/rest/v1/${pathAndQuery}`;
62	    const res = await fetch(url, { method: 'GET', headers });
63	    const text = await res.text();
64	    let parsed;
65	    try {
66	        parsed = text ? JSON.parse(text) : null;
67	    } catch {
68	        parsed = text;
69	    }
70	    return { ok: res.ok, status: res.status, body: parsed };
71	}
72	
73	async function restPostRpc(functionName, payload) {
74	    const url = `${SUPABASE_URL}/rest/v1/rpc/${functionName}`;
75	    const res = await fetch(url, {
76	        method: 'POST',
77	        headers,
78	        body: JSON.stringify(payload),
79	    });
80	    const text = await res.text();
81	    let parsed;
82	    try {
83	        parsed = text ? JSON.parse(text) : null;
84	    } catch {
85	        parsed = text;
86	    }
87	    return { ok: res.ok, status: res.status, body: parsed };
88	}
89	
90	function buildZeroVectorLiteral(dim = 384) {
91	    const parts = new Array(dim).fill('0');
92	    return `[${parts.join(',')}]`;
93	}
94	
95	async function resolveAnyCustomerId() {
96	    const uuidRe = /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i;
97	
98	    const fromContexts = await restGet('dim_contexts?select=customer_id&customer_id=not.is.null&limit=10');
99	    if (fromContexts.ok && Array.isArray(fromContexts.body) && fromContexts.body.length > 0) {
100	        for (const row of fromContexts.body) {
101	            const id = typeof row?.customer_id === 'string' ? row.customer_id.trim() : '';
102	            if (uuidRe.test(id)) return id;
103	        }
104	    }
105	
106	    const fromCustomers = await restGet('dim_customers?select=customer_id&customer_id=not.is.null&limit=10');
107	    if (fromCustomers.ok && Array.isArray(fromCustomers.body) && fromCustomers.body.length > 0) {
108	        for (const row of fromCustomers.body) {
109	            const id = typeof row?.customer_id === 'string' ? row.customer_id.trim() : '';
110	            if (uuidRe.test(id)) return id;
111	        }
112	    }
113	
114	    return null;
115	}
