117	async function main() {
118	    const checks = [];
119	    let failed = false;
120	
121	    // Check 1: context-aware MV is readable
122	    const mvContext = await restGet('mv_task_action_performance_context?select=*&limit=1');
123	    checks.push({
124	        name: 'mv_task_action_performance_context read',
125	        ok: mvContext.ok,
126	        detail: mvContext.ok
127	            ? `ok (rows=${Array.isArray(mvContext.body) ? mvContext.body.length : 0})`
128	            : `status=${mvContext.status}`,
129	    });
130	    if (!mvContext.ok) failed = true;
131	
132	    // Check 2: global MV is readable
133	    const mvGlobal = await restGet('mv_task_action_performance_180d?select=*&limit=1');
134	    checks.push({
135	        name: 'mv_task_action_performance_180d read',
136	        ok: mvGlobal.ok,
137	        detail: mvGlobal.ok
138	            ? `ok (rows=${Array.isArray(mvGlobal.body) ? mvGlobal.body.length : 0})`
139	            : `status=${mvGlobal.status}`,
140	    });
141	    if (!mvGlobal.ok) failed = true;
142	
143	    // Check 3: sample embedded context for RPC probe
144	    const contextSample = await restGet(
145	        'dim_contexts?select=context_id,customer_id,embedding_model,embedding_schema_version,context_vector&context_vector=not.is.null&order=created_at.desc&limit=1'
146	    );
147	
148	    if (!contextSample.ok) {
149	        checks.push({
150	            name: 'dim_contexts sample read',
151	            ok: false,
152	            detail: `status=${contextSample.status}`,
153	        });
154	        failed = true;
155	    } else {
156	        const rows = Array.isArray(contextSample.body) ? contextSample.body : [];
157	        if (rows.length === 0) {
158	            checks.push({
159	                name: 'dim_contexts sample read',
160	                ok: true,
161	                detail: 'ok (no embedded contexts yet; using zero-vector RPC probe)',
162	            });
163	
164	            const fallbackCustomerId = await resolveAnyCustomerId();
165	            if (!fallbackCustomerId) {
166	                checks.push({
167	                    name: 'match_context_vector RPC probe',
168	                    ok: false,
169	                    detail: 'no customer_id available for RPC probe',
170	                });
171	                failed = true;
172	            } else {
173	                const rpc = await restPostRpc('match_context_vector', {
174	                    query_vector: buildZeroVectorLiteral(384),
175	                    p_customer_id: fallbackCustomerId,
176	                    p_model: 'gte-small',
177	                    p_threshold: 0,
178	                    p_limit: 1,
179	                    p_schema_version: 2,
180	                });
181	
182	                const rpcRows = Array.isArray(rpc.body) ? rpc.body : [];
183	                checks.push({
184	                    name: 'match_context_vector RPC probe',
185	                    ok: rpc.ok,
186	                    detail: rpc.ok
187	                        ? `ok (callable, rows=${rpcRows.length})`
188	                        : `status=${rpc.status}; body=${typeof rpc.body === 'string' ? rpc.body : JSON.stringify(rpc.body)}`,
189	                });
190	
191	                if (!rpc.ok) {
192	                    failed = true;
193	                }
194	            }
195	        } else {
196	            const row = rows[0];
197	            const vectorLiteral = toVectorLiteral(row.context_vector);
198	            const dim = vectorDimensionFromLiteral(vectorLiteral);
199	
200	            checks.push({
201	                name: 'dim_contexts sample read',
202	                ok: !!vectorLiteral,
203	                detail: vectorLiteral
204	                    ? `ok (context_id=${row.context_id}, dim=${dim})`
205	                    : 'context_vector parse failed',
206	            });
207	            if (!vectorLiteral) {
208	                failed = true;
209	            } else {
210	                const rpc = await restPostRpc('match_context_vector', {
211	                    query_vector: vectorLiteral,
212	                    p_customer_id: row.customer_id,
213	                    p_model: row.embedding_model || 'gte-small',
214	                    p_threshold: 0,
215	                    p_limit: 1,
216	                    p_schema_version: Number(row.embedding_schema_version || 2),
217	                });
218	
219	                const rpcRows = Array.isArray(rpc.body) ? rpc.body : [];
220	                const top = rpcRows[0] || null;
221	                const similarity = top && typeof top.similarity === 'number' ? top.similarity : null;
222	                const similarityOk = similarity === null ? false : similarity >= 0 && similarity <= 1;
223	
224	                checks.push({
225	                    name: 'match_context_vector RPC probe',
226	                    ok: rpc.ok && rpcRows.length > 0 && similarityOk,
227	                    detail: rpc.ok
228	                        ? `ok (rows=${rpcRows.length}, top_similarity=${similarity ?? 'n/a'})`
229	                        : `status=${rpc.status}`,
230	                });
231	
232	                if (!(rpc.ok && rpcRows.length > 0 && similarityOk)) {
233	                    failed = true;
234	                }
235	            }
236	        }
237	    }
238	
239	    console.log('LIVE_SMOKE_CHECK_RESULTS_START');
240	    for (const check of checks) {
241	        const status = check.ok ? 'PASS' : 'FAIL';
242	        console.log(`${status} | ${check.name} | ${check.detail}`);
243	    }
244	    console.log('LIVE_SMOKE_CHECK_RESULTS_END');
245	
246	    if (failed) {
247	        process.exit(1);
248	    }
249	}
250	
251	main().catch((err) => {
252	    console.error('Smoke check crashed:', err?.message || err);
253	    process.exit(1);
254	});
