1	#!/usr/bin/env node
2	
3	const fs = require('node:fs');
4	const path = require('node:path');
5	const cp = require('node:child_process');
6	
7	const SECRET_PATTERNS = [
8	    {
9	        name: 'Supabase PAT',
10	        regex: /\bsbp_[A-Za-z0-9]{24,}\b/g,
11	    },
12	    {
13	        name: 'OpenAI project key',
14	        regex: /\bsk-proj-[A-Za-z0-9_-]{20,}\b/g,
15	    },
16	    {
17	        name: 'Layerinfinite API key',
18	        regex: /\blayerinfinite_[A-Za-z0-9]{24,}\b/g,
19	    },
20	];
21	
22	const IGNORE_FILE_PARTS = [
23	    'node_modules/',
24	    '.venv/',
25	    'dist/',
26	    '.git/',
27	    '.next/',
28	];
29	
30	const IGNORE_LINE_HINTS = [
31	    'example',
32	    'replace',
33	    'placeholder',
34	    'testkey',
35	    'dummy',
36	    'xxxx',
37	    'YOUR_',
38	    'your_',
39	    '***',
40	];
41	
42	function listCandidateFiles() {
43	    const out = cp.execSync('git ls-files --cached --others --exclude-standard', { encoding: 'utf8' });
44	    return out
45	        .split(/\r?\n/)
46	        .map((s) => s.trim())
47	        .filter(Boolean)
48	        .filter((file, index, arr) => arr.indexOf(file) === index)
49	        .filter((file) => !IGNORE_FILE_PARTS.some((part) => file.includes(part)));
50	}
51	
52	function shouldIgnoreLine(line) {
53	    const lower = line.toLowerCase();
54	    return IGNORE_LINE_HINTS.some((hint) => lower.includes(String(hint).toLowerCase()));
55	}
56	
57	function scanFile(filePath) {
58	    const absolutePath = path.resolve(filePath);
59	    let content;
60	    try {
61	        content = fs.readFileSync(absolutePath, 'utf8');
62	    } catch {
63	        return [];
64	    }
65	
66	    const findings = [];
67	    const lines = content.split(/\r?\n/);
68	
69	    lines.forEach((line, index) => {
70	        if (shouldIgnoreLine(line)) return;
71	
72	        for (const pattern of SECRET_PATTERNS) {
73	            pattern.regex.lastIndex = 0;
74	            const match = pattern.regex.exec(line);
75	            if (match) {
76	                findings.push({
77	                    filePath,
78	                    line: index + 1,
79	                    pattern: pattern.name,
80	                    snippet: line.trim().slice(0, 160),
81	                });
82	            }
83	        }
84	    });
85	
86	    return findings;
87	}
88	
89	function main() {
90	    const files = listCandidateFiles();
91	    const findings = [];
92	
93	    for (const file of files) {
94	        findings.push(...scanFile(file));
95	    }
96	
97	    if (findings.length) {
98	        console.error('Tracked-secret scan failed. Potential hardcoded secrets found:');
99	        for (const finding of findings) {
100	            console.error(`- ${finding.filePath}:${finding.line} [${finding.pattern}] ${finding.snippet}`);
101	        }
102	        process.exit(1);
103	    }
104	
105	    console.log('Tracked-secret scan passed.');
106	}
107	
108	main();
