3	function parseIssues(raw) {
4	    if (!raw) return ['payment_failed', 'network_timeout', 'env_var_missing'];
5	    return String(raw)
6	        .split(',')
7	        .map((s) => s.trim())
8	        .filter(Boolean);
9	}
10	
11	function buildUrl(base, issueType, episodeId) {
12	    const url = new URL('/v1/get-scores', base);
13	    url.searchParams.set('issue_type', issueType);
14	    url.searchParams.set('environment', 'production');
15	    if (episodeId) {
16	        url.searchParams.set('episode_id', episodeId);
17	    }
18	    return url.toString();
19	}
20	
21	function uuidLike(value) {
22	    return typeof value === 'string' && /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(value);
23	}
24	
25	async function callGetScores(baseUrl, apiKey, issueType, episodeId) {
26	    const response = await fetch(buildUrl(baseUrl, issueType, episodeId), {
27	        method: 'GET',
28	        headers: {
29	            Accept: 'application/json',
30	            'X-API-Key': apiKey,
31	        },
32	    });
33	
34	    let data = null;
35	    try {
36	        data = await response.json();
37	    } catch {
38	        data = null;
39	    }
40	
41	    return { response, data };
42	}
43	
44	async function main() {
45	    const baseUrl = process.env.PRIMARY_API_URL
46	        || process.env.LAYERINFINITE_BASE_URL
47	        || process.env.LAYERINFINITE_API_URL
48	        || 'https://layerinfinite.me';
49	
50	    const apiKey = process.env.LAYERINFINITE_API_KEY;
51	    const issues = parseIssues(process.env.DECISION_CHECK_ISSUES);
52	
53	    if (!apiKey) {
54	        console.error('LAYERINFINITE_API_KEY is required.');
55	        process.exit(1);
56	    }
57	
58	    console.log('=== Decision Linkage Check ===');
59	    console.log(`Base URL: ${baseUrl}`);
60	    console.log(`Issues: ${issues.join(', ')}`);
61	
62	    const failures = [];
63	
64	    // Main check: standard calls without episode_id should emit decision_id.
65	    for (const issue of issues) {
66	        const { response, data } = await callGetScores(baseUrl, apiKey, issue, null);
67	        const decisionId = data?.decision_id ?? null;
68	
69	        console.log(`issue=${issue} status=${response.status} decision_id=${decisionId ?? 'null'}`);
70	
71	        if (!response.ok) {
72	            failures.push(`get-scores failed for ${issue} (HTTP ${response.status})`);
73	            continue;
74	        }
75	
76	        if (!uuidLike(decisionId)) {
77	            failures.push(`decision_id missing for ${issue} (no episode_id request)`);
78	        }
79	    }
80	
81	    // Control check: episode_id path should also emit decision_id.
82	    const controlEpisodeId = crypto.randomUUID();
83	    const controlIssue = issues[0];
84	    const control = await callGetScores(baseUrl, apiKey, controlIssue, controlEpisodeId);
85	    const controlDecisionId = control.data?.decision_id ?? null;
86	
87	    console.log(
88	        `control issue=${controlIssue} episode_id=yes status=${control.response.status} decision_id=${controlDecisionId ?? 'null'}`,
89	    );
90	
91	    if (!control.response.ok) {
92	        failures.push(`control get-scores failed (HTTP ${control.response.status})`);
93	    } else if (!uuidLike(controlDecisionId)) {
94	        failures.push('control request with episode_id did not emit decision_id');
95	    }
96	
97	    if (failures.length > 0) {
98	        console.error('Result: FAIL');
99	        for (const failure of failures) {
100	            console.error(`- ${failure}`);
101	        }
102	        process.exit(1);
103	    }
104	
105	    console.log('Result: PASS');
106	}
